package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.rkm.rekenmotor.CoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.rkm.rekenmotor.dto.EvbDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionParamKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionType;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenAtoom;
import be.schaubroeck.lpb.rkm.rekenmotor.service.CoreHrConfigurationService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.LockLogHelper;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenBatchNrGenerator;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenenHelpService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenmotorDtoConverter;
import be.schaubroeck.lpb.rkm.rekenmotor.service.web.RekenProcesImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MetaRekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.LockLog;
import be.schaubroeck.lpb.tools.api.dto.LockLogDTO;
import be.schaubroeck.lpb.tools.enums.LockItemId;
import be.schaubroeck.lpb.tools.enums.LockType;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.enumtypes.StatusVoorbereiding;
import be.schaubroeck.lpb.tools.exception.LockingException;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.exception.ProcesHaltedException;
import be.schaubroeck.lpb.tools.service.LockLogService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import com.google.common.collect.ImmutableList;
import com.google.common.collect.SetMultimap;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Optional;

@Slf4j
public class StandaardRekenUitVoorbereidingService implements RekenUitVoorbereidingService {

    private static final List<LockLogDTO> LOCKS = ImmutableList
            .of(new LockLogDTO(LockItemId.ALLPID, 0, LockType.SHARED), new LockLogDTO(LockItemId.ALLREKENAGENDA, 0, LockType.SHARED),
                    new LockLogDTO(LockItemId.ALLWACHTAGENDA, 0, LockType.SHARED), new LockLogDTO(LockItemId.ALLMT, 0, LockType.EXCLUSIVE));

    @Autowired
    private LockLogService lockLogService;
    @Autowired
    private RekenBatchNrGenerator rekenBatchNrGenerator;
    @Autowired
    private VoorbereidingStatusService voorbereidingStatusService;
    @Autowired
    private AlgemeneRekenUitVoorbereidingService rekenUitVoorbereidingService;
    @Autowired
    private RekenenHelpService rekenenHelpService;
    @Autowired
    private CoreHrConfigurationService coreHrConfigurationService;

    @Override
    public MetaRekenFeedback start(Admin admin, String actor, RekenContext actionParams) {
        Rekenmodus rekenmodus = bepaalDeRekenModus(actionParams);
        Collection<ElektronischeVoorbereiding> voorbereidingen = haalVoorbereidingenOpAndersGooiFoutBoodschap(actionParams);

        return doeBerekeningen(admin, voorbereidingen, rekenmodus, actor);
    }

    private Collection<ElektronischeVoorbereiding> haalVoorbereidingenOpAndersGooiFoutBoodschap(RekenContext actionParams) {
        Optional<Collection<ElektronischeVoorbereiding>> optionalVoorbereidingen =
                Optional.ofNullable(actionParams.getUnchecked(RekenActionParamKey.VOORBEREIDINGEN_KEY));
        return optionalVoorbereidingen
                .orElseThrow(() -> new MessageException("RekenUitVoorbereidingService.run onvoldoende parameters"));
    }

    private Rekenmodus bepaalDeRekenModus(RekenContext actionParams) {
        Optional<Rekenmodus> optionalRekenmodus = Optional.ofNullable(actionParams.getUnchecked(RekenActionParamKey.REKENMODUS_KEY));
        return optionalRekenmodus.orElse(Rekenmodus.NORMAAL);
    }

    @Override
    @InitializeAdmin
    public MetaRekenFeedback doeBerekeningen(Admin admin, Collection<ElektronischeVoorbereiding> eVoorbereidingen, Rekenmodus modus, String actor) {
        MetaRekenFeedback metaFeedback = new MetaRekenFeedback(RekenActionType.REKEN_UIT_VOORBEREIDING, modus);
        List<RekenVoorbereiding> voorbereidingen = rekenUitVoorbereidingService.maakVoorbereidingen(eVoorbereidingen, admin);
        RekenmotorDtoConverter converter = rekenUitVoorbereidingService.getConverter(admin);
        CoreHrConfiguratie coreHrConfiguratie = coreHrConfigurationService.getCoreHrConfiguratie(admin);
        List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties = coreHrConfiguratie.getRkmCoreHrConfiguraties();
        List<EvbDTO> evbDTOS = converter.convertVoorbereidingen(voorbereidingen);
        List<LockLog> lockedItems = new ArrayList<>();
        Integer rekenBatchNr = 0;

        try {
            lockedItems = lockLogService.lockItems(admin, LOCKS, actor);
            rekenBatchNr = generateRekenBatchNr();
            updateVoorbereidingStatus(voorbereidingen, rekenBatchNr, StatusVoorbereiding.RM2_BEZIG_MET_REKENEN, actor);
            Thread.sleep(1000);
            CacheContext.getInstance().clearCachedServices(Scope.ALL);
            log.trace("doeBerekeningen(adminid:{} ({});", admin.getId(), admin.getAdminDirTrimmed());
            checkInterupted();
            SetMultimap<RekenAtoom, Integer> rekenAtomen = rekenUitVoorbereidingService.bepaalRekenAtomen(rkmCoreHrConfiguraties, voorbereidingen, converter);
            schatAantalMaandOpdrachten(rekenAtomen);
            metaFeedback.zetRekenAtomenEnvoorbereidingen(rekenAtomen, evbDTOS);
            RekenUitVoorbereidingStatus rekenUitVoorbereidingStatus =
                    rekenUitVoorbereidingService.doeBerekeningenUitRekenAgenda(admin, rekenBatchNr, rekenAtomen, actor, metaFeedback, coreHrConfiguratie);
            updateVoorbereidingStatus(voorbereidingen, rekenBatchNr,
                    voorbereidingStatusService.bepaalStatusVoorbereiding(rekenUitVoorbereidingStatus.status, rekenUitVoorbereidingStatus.heeftReguls,
                            rekenUitVoorbereidingStatus.heeftWaarschuwingen), actor);

            rekenAtomen.keySet().stream()
                    .map(RekenAtoom::getPersoonId)
                    .distinct()
                    .forEach(persoonId -> rekenenHelpService.verwijderRegulsZonderOverlappendeOpdracht(admin, persoonId));
        } catch (LockingException lockingException) {
            log.debug("LockingException tijdens doeBerekeningen.", lockingException);
            RekenProcesImp.setStatusWaitingForLockStatic();
            updateVoorbereidingStatus(voorbereidingen, rekenBatchNr, StatusVoorbereiding.RM2_REKENEN_LOCKED, actor);
        } catch (Exception exception) {
            log.error("Exception tijdens doeBerekeningen.", exception);
            updateVoorbereidingStatus(voorbereidingen, rekenBatchNr, StatusVoorbereiding.RM2_GEREKEND_MET_FOUTEN, actor);
        } finally {
            LockLogHelper lockLogHelper = new LockLogHelper(lockLogService, log);
            lockLogHelper.unlockItems(admin, lockedItems);
        }
        return metaFeedback;
    }

    private Integer generateRekenBatchNr() {
        Integer rekenBatchNr = 0;
        try {
            rekenBatchNr = rekenBatchNrGenerator.generateRekenBatchNr();
        } catch (Exception exception) {
            log.warn("Gneratie van rekenBatchNr faalde");
        }
        return rekenBatchNr;
    }

    private void updateVoorbereidingStatus(
            Collection<RekenVoorbereiding> voorbereidingen, Integer rekenBatchNr, StatusVoorbereiding status, String actor) {
        for (RekenVoorbereiding voorbereiding : voorbereidingen) {
            voorbereidingStatusService.updateVoorbereidingStatus(voorbereiding, rekenBatchNr, status, actor);
        }
    }

    private void schatAantalMaandOpdrachten(SetMultimap<RekenAtoom, Integer> rekenAtomen) {
        int totaal = rekenAtomen.keySet().size();
        if (totaal != 0) {
            RekenProcesImp.setTotaalStatic(totaal);
        } else {
            log.trace("Lege berekening");
            RekenProcesImp.setTotaalStatic(1);
            RekenProcesImp.incrementVerwerktStatic();
        }
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }
}
